/* CSS Reset - 重置浏览器默认样式 */

* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

html {
    font-size: 16px;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
    line-height: 1.6;
    overflow-x: hidden;
}

ul, ol {
    list-style: none;
}

a {
    text-decoration: none;
    color: inherit;
}

button {
    border: none;
    background: none;
    cursor: pointer;
    font-family: inherit;
}

input, textarea {
    font-family: inherit;
    font-size: inherit;
}

img {
    max-width: 100%;
    height: auto;
    display: block;
}

:focus {
    outline: none;
}

:focus-visible {
    outline: 2px solid var(--primary-color);
    outline-offset: 2px;
}

/* CSS 变量定义 - 主题颜色和设计令牌 */

:root {
    /* 主色调 */
    --primary-color: #4a90d9;
    --primary-hover: #357abd;
    --primary-light: #e8f2fc;

    /* 状态颜色 */
    --success-color: #5cb85c;
    --danger-color: #d9534f;
    --warning-color: #f0ad4e;
    --info-color: #5bc0de;

    /* 浅色主题 */
    --bg-primary: #ffffff;
    --bg-secondary: #f8f9fa;
    --bg-tertiary: #e9ecef;

    --text-primary: #212529;
    --text-secondary: #6c757d;
    --text-tertiary: #adb5bd;

    --border-color: #dee2e6;
    --shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
    --shadow-lg: 0 4px 16px rgba(0, 0, 0, 0.15);

    /* 尺寸 */
    --spacing-xs: 0.25rem;
    --spacing-sm: 0.5rem;
    --spacing-md: 1rem;
    --spacing-lg: 1.5rem;
    --spacing-xl: 2rem;

    --radius-sm: 4px;
    --radius-md: 8px;
    --radius-lg: 12px;

    /* 过渡 */
    --transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);

    /* 字体大小 */
    --font-sm: 0.875rem;
    --font-base: 1rem;
    --font-lg: 1.125rem;
    --font-xl: 1.5rem;
    --font-2xl: 2rem;
}

/* 深色主题 */
[data-theme="dark"] {
    --bg-primary: #1a1a1a;
    --bg-secondary: #2d2d2d;
    --bg-tertiary: #3d3d3d;

    --text-primary: #e9ecef;
    --text-secondary: #adb5bd;
    --text-tertiary: #6c757d;

    --border-color: #495057;
    --shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    --shadow-lg: 0 4px 16px rgba(0, 0, 0, 0.4);

    --primary-light: #2c3e50;
}

/* 布局样式 - 页面整体布局 */

body {
    min-height: 100vh;
    background: var(--bg-secondary);
    color: var(--text-primary);
    transition: var(--transition);
}

.app-container {
    max-width: 800px;
    margin: 0 auto;
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    background: var(--bg-primary);
    box-shadow: var(--shadow-lg);
}

/* 头部 */
.app-header {
    padding: var(--spacing-lg) var(--spacing-xl);
    background: linear-gradient(135deg, var(--primary-color), var(--primary-hover));
    color: white;
    display: flex;
    justify-content: space-between;
    align-items: center;
    box-shadow: var(--shadow);
}

.app-header h1 {
    font-size: var(--font-2xl);
    font-weight: 600;
}

.header-actions {
    display: flex;
    gap: var(--spacing-md);
}

/* 主体内容 */
.app-main {
    flex: 1;
    padding: var(--spacing-xl);
    display: flex;
    flex-direction: column;
    gap: var(--spacing-lg);
}

.todo-input-section {
    width: 100%;
}

.todo-filters {
    display: flex;
    gap: var(--spacing-sm);
    justify-content: center;
    flex-wrap: wrap;
}

.todo-stats {
    display: flex;
    justify-content: space-between;
    align-items: center;
    flex-wrap: wrap;
    gap: var(--spacing-md);
    padding: var(--spacing-md);
    background: var(--bg-secondary);
    border-radius: var(--radius-md);
}

.todo-list-section {
    flex: 1;
    min-height: 300px;
}

/* 底部 */
.app-footer {
    padding: var(--spacing-lg);
    text-align: center;
    background: var(--bg-secondary);
    color: var(--text-secondary);
    font-size: var(--font-sm);
    border-top: 1px solid var(--border-color);
}

/* 响应式 */
@media (max-width: 600px) {
    .app-main {
        padding: var(--spacing-lg);
    }

    .app-header {
        padding: var(--spacing-md) var(--spacing-lg);
        flex-direction: column;
        gap: var(--spacing-sm);
        text-align: center;
    }

    .app-header h1 {
        font-size: var(--font-xl);
    }

    .todo-stats {
        flex-direction: column;
        align-items: stretch;
    }

    .stats-item {
        text-align: center;
    }
}

/* 组件样式 - 可复用UI组件 */

/* 表单 */
.todo-form {
    display: flex;
    gap: var(--spacing-md);
    width: 100%;
}

.todo-input {
    flex: 1;
    padding: var(--spacing-md);
    font-size: var(--font-base);
    border: 2px solid var(--border-color);
    border-radius: var(--radius-md);
    background: var(--bg-primary);
    color: var(--text-primary);
    transition: var(--transition);
}

.todo-input:focus {
    border-color: var(--primary-color);
    box-shadow: 0 0 0 3px var(--primary-light);
}

.todo-input::placeholder {
    color: var(--text-tertiary);
}

/* 按钮 */
.btn {
    padding: var(--spacing-md) var(--spacing-lg);
    font-size: var(--font-base);
    font-weight: 500;
    border-radius: var(--radius-md);
    cursor: pointer;
    transition: var(--transition);
    display: inline-flex;
    align-items: center;
    gap: var(--spacing-sm);
    white-space: nowrap;
}

.btn-primary {
    background: var(--primary-color);
    color: white;
}

.btn-primary:hover {
    background: var(--primary-hover);
    transform: translateY(-1px);
    box-shadow: var(--shadow);
}

.btn-secondary {
    background: var(--bg-tertiary);
    color: var(--text-primary);
}

.btn-secondary:hover {
    background: var(--border-color);
}

.btn-small {
    padding: var(--spacing-sm) var(--spacing-md);
    font-size: var(--font-sm);
}

.btn-icon {
    font-size: var(--font-lg);
    line-height: 1;
}

.btn-text {
    line-height: 1;
}

/* 筛选按钮 */
.filter-btn {
    padding: var(--spacing-sm) var(--spacing-lg);
    font-size: var(--font-base);
    border-radius: var(--radius-lg);
    background: var(--bg-secondary);
    color: var(--text-secondary);
    transition: var(--transition);
}

.filter-btn:hover {
    background: var(--bg-tertiary);
    color: var(--text-primary);
}

.filter-btn.active {
    background: var(--primary-color);
    color: white;
}

/* 待办事项列表 */
.todo-list {
    list-style: none;
    display: flex;
    flex-direction: column;
    gap: var(--spacing-md);
}

.todo-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-md);
    padding: var(--spacing-md) var(--spacing-lg);
    background: var(--bg-secondary);
    border-radius: var(--radius-md);
    border: 2px solid transparent;
    transition: var(--transition);
    animation: slideIn 0.3s ease;
}

@keyframes slideIn {
    from {
        opacity: 0;
        transform: translateY(-10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.todo-item:hover {
    border-color: var(--primary-color);
    box-shadow: var(--shadow);
}

.todo-item.completed {
    opacity: 0.6;
}

.todo-item.completed .todo-text {
    text-decoration: line-through;
    color: var(--text-tertiary);
}

/* 复选框 */
.todo-checkbox {
    width: 20px;
    height: 20px;
    border: 2px solid var(--border-color);
    border-radius: var(--radius-sm);
    cursor: pointer;
    transition: var(--transition);
    flex-shrink: 0;
    position: relative;
}

.todo-checkbox:hover {
    border-color: var(--primary-color);
}

.todo-checkbox.checked {
    background: var(--success-color);
    border-color: var(--success-color);
}

.todo-checkbox.checked::after {
    content: '✓';
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    color: white;
    font-size: var(--font-sm);
    font-weight: bold;
}

/* 待办事项文本 */
.todo-text {
    flex: 1;
    font-size: var(--font-base);
    color: var(--text-primary);
    word-break: break-word;
    line-height: 1.5;
}

.todo-text.editing {
    display: none;
}

.todo-edit-input {
    flex: 1;
    padding: var(--spacing-sm);
    font-size: var(--font-base);
    border: 2px solid var(--primary-color);
    border-radius: var(--radius-sm);
    background: var(--bg-primary);
    color: var(--text-primary);
}

/* 删除按钮 */
.todo-delete {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: var(--radius-sm);
    color: var(--text-tertiary);
    transition: var(--transition);
    flex-shrink: 0;
}

.todo-delete:hover {
    background: var(--danger-color);
    color: white;
}

/* 编辑按钮 */
.todo-edit {
    width: 32px;
    height: 32px;
    display: flex;
    align-items: center;
    justify-content: center;
    border-radius: var(--radius-sm);
    color: var(--text-tertiary);
    transition: var(--transition);
    flex-shrink: 0;
}

.todo-edit:hover {
    background: var(--primary-color);
    color: white;
}

/* 空状态 */
.empty-state {
    text-align: center;
    padding: var(--spacing-xl);
    color: var(--text-tertiary);
}

.empty-icon {
    font-size: 4rem;
    margin-bottom: var(--spacing-md);
}

.empty-text {
    font-size: var(--font-lg);
}

/* 统计信息 */
.stats-item {
    display: flex;
    align-items: center;
    gap: var(--spacing-sm);
    font-size: var(--font-base);
    color: var(--text-secondary);
}

.stats-count {
    font-weight: 600;
    color: var(--primary-color);
    font-size: var(--font-lg);
}

/* 主题切换按钮 */
.theme-toggle {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background: rgba(255, 255, 255, 0.2);
    color: white;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: var(--transition);
}

.theme-toggle:hover {
    background: rgba(255, 255, 255, 0.3);
    transform: scale(1.1);
}

.theme-icon {
    font-size: var(--font-xl);
}

/* 响应式调整 */
@media (max-width: 600px) {
    .todo-form {
        flex-direction: column;
    }

    .btn-text {
        display: none;
    }

    .todo-item {
        padding: var(--spacing-sm) var(--spacing-md);
    }

    .todo-edit,
    .todo-delete {
        width: 28px;
        height: 28px;
    }
}

/* 主题样式 - 主题切换相关样式 */

/* 主题过渡效果 */
body {
    transition: background-color 0.3s ease, color 0.3s ease;
}

.app-container {
    transition: box-shadow 0.3s ease, background-color 0.3s ease;
}

/* 浅色主题（默认） */
:root {
    /* 由 variables.css 定义 */
}

/* 深色主题 */
[data-theme="dark"] {
    color-scheme: dark;
}

/* 主题切换动画 */
@keyframes themeSwitch {
    0% {
        opacity: 0;
    }
    100% {
        opacity: 1;
    }
}

.theme-switching {
    animation: themeSwitch 0.3s ease;
}

/* 主题图标动画 */
.theme-toggle .theme-icon {
    transition: transform 0.3s ease, content 0.3s ease;
}

.theme-toggle:hover .theme-icon {
    transform: rotate(20deg) scale(1.1);
}

/* 滚动条样式 */
::-webkit-scrollbar {
    width: 8px;
}

::-webkit-scrollbar-track {
    background: var(--bg-secondary);
}

::-webkit-scrollbar-thumb {
    background: var(--border-color);
    border-radius: 4px;
}

::-webkit-scrollbar-thumb:hover {
    background: var(--text-tertiary);
}

/* 选择文本样式 */
::selection {
    background: var(--primary-color);
    color: white;
}

/**
 * localStorage 封装工具类
 * 提供安全的本地存储操作
 */

class Storage {
    constructor() {
        this.prefix = 'todolist_';
        this.available = this.checkAvailability();
    }

    /**
     * 检查 localStorage 是否可用
     */
    checkAvailability() {
        try {
            const test = '__storage_test__';
            localStorage.setItem(test, test);
            localStorage.removeItem(test);
            return true;
        } catch (e) {
            console.warn('localStorage is not available:', e);
            return false;
        }
    }

    /**
     * 生成完整的键名
     */
    getKey(key) {
        return `${this.prefix}${key}`;
    }

    /**
     * 存储数据
     */
    set(key, value) {
        if (!this.available) {
            console.warn('localStorage is not available');
            return false;
        }

        try {
            const serialized = JSON.stringify(value);
            localStorage.setItem(this.getKey(key), serialized);
            return true;
        } catch (e) {
            console.error('Error saving to localStorage:', e);
            return false;
        }
    }

    /**
     * 获取数据
     */
    get(key, defaultValue = null) {
        if (!this.available) {
            return defaultValue;
        }

        try {
            const item = localStorage.getItem(this.getKey(key));
            return item ? JSON.parse(item) : defaultValue;
        } catch (e) {
            console.error('Error reading from localStorage:', e);
            return defaultValue;
        }
    }

    /**
     * 删除数据
     */
    remove(key) {
        if (!this.available) {
            return false;
        }

        try {
            localStorage.removeItem(this.getKey(key));
            return true;
        } catch (e) {
            console.error('Error removing from localStorage:', e);
            return false;
        }
    }

    /**
     * 清空所有存储数据
     */
    clear() {
        if (!this.available) {
            return false;
        }

        try {
            Object.keys(localStorage)
                .filter(key => key.startsWith(this.prefix))
                .forEach(key => localStorage.removeItem(key));
            return true;
        } catch (e) {
            console.error('Error clearing localStorage:', e);
            return false;
        }
    }
}

export default new Storage();

/**
 * DOM 操作工具类
 * 提供常用的 DOM 操作方法
 */

class DOMHelper {
    /**
     * 查询元素
     */
    static $(selector, parent = document) {
        return parent.querySelector(selector);
    }

    /**
     * 查询多个元素
     */
    static $$(selector, parent = document) {
        return Array.from(parent.querySelectorAll(selector));
    }

    /**
     * 创建元素
     */
    static createElement(tag, className = '', textContent = '') {
        const element = document.createElement(tag);
        if (className) element.className = className;
        if (textContent) element.textContent = textContent;
        return element;
    }

    /**
     * 添加事件监听
     */
    static on(element, event, handler, options = {}) {
        element.addEventListener(event, handler, options);
    }

    /**
     * 移除事件监听
     */
    static off(element, event, handler) {
        element.removeEventListener(event, handler);
    }

    /**
     * 添加类名
     */
    static addClass(element, className) {
        element.classList.add(className);
    }

    /**
     * 移除类名
     */
    static removeClass(element, className) {
        element.classList.remove(className);
    }

    /**
     * 切换类名
     */
    static toggleClass(element, className) {
        element.classList.toggle(className);
    }

    /**
     * 检查是否包含类名
     */
    static hasClass(element, className) {
        return element.classList.contains(className);
    }

    /**
     * 设置属性
     */
    static setAttribute(element, name, value) {
        element.setAttribute(name, value);
    }

    /**
     * 获取属性
     */
    static getAttribute(element, name) {
        return element.getAttribute(name);
    }

    /**
     * 移除属性
     */
    static removeAttribute(element, name) {
        element.removeAttribute(name);
    }

    /**
     * 显示元素
     */
    static show(element) {
        element.style.display = '';
    }

    /**
     * 隐藏元素
     */
    static hide(element) {
        element.style.display = 'none';
    }

    /**
     * 淡入动画
     */
    static fadeIn(element, duration = 300) {
        element.style.opacity = '0';
        element.style.display = '';
        element.style.transition = `opacity ${duration}ms`;

        requestAnimationFrame(() => {
            element.style.opacity = '1';
        });
    }

    /**
     * 淡出动画
     */
    static fadeOut(element, duration = 300) {
        element.style.transition = `opacity ${duration}ms`;
        element.style.opacity = '0';

        setTimeout(() => {
            element.style.display = 'none';
        }, duration);
    }

    /**
     * 添加动画类
     */
    static animate(element, animationName, duration = 300) {
        element.style.animation = `${animationName} ${duration}ms ease`;
        setTimeout(() => {
            element.style.animation = '';
        }, duration);
    }

    /**
     * 获取元素尺寸
     */
    static getSize(element) {
        const rect = element.getBoundingClientRect();
        return {
            width: rect.width,
            height: rect.height,
            top: rect.top,
            left: rect.left
        };
    }

    /**
     * 设置HTML内容
     */
    static setHTML(element, html) {
        element.innerHTML = html;
    }

    /**
     * 设置文本内容
     */
    static setText(element, text) {
        element.textContent = text;
    }

    /**
     * 获取表单数据
     */
    static getFormData(form) {
        const formData = new FormData(form);
        const data = {};
        for (const [key, value] of formData.entries()) {
            data[key] = value;
        }
        return data;
    }

    /**
     * 防抖函数
     */
    static debounce(func, wait = 300) {
        let timeout;
        return function executedFunction(...args) {
            const later = () => {
                clearTimeout(timeout);
                func(...args);
            };
            clearTimeout(timeout);
            timeout = setTimeout(later, wait);
        };
    }

    /**
     * 节流函数
     */
    static throttle(func, limit = 300) {
        let inThrottle;
        return function(...args) {
            if (!inThrottle) {
                func.apply(this, args);
                inThrottle = true;
                setTimeout(() => inThrottle = false, limit);
            }
        };
    }
}

export default DOMHelper;

/**
 * 日期工具类
 * 提供日期格式化和处理功能
 */

class DateUtils {
    /**
     * 格式化日期
     */
    static format(date, format = 'YYYY-MM-DD HH:mm:ss') {
        const d = new Date(date);
        const year = d.getFullYear();
        const month = String(d.getMonth() + 1).padStart(2, '0');
        const day = String(d.getDate()).padStart(2, '0');
        const hours = String(d.getHours()).padStart(2, '0');
        const minutes = String(d.getMinutes()).padStart(2, '0');
        const seconds = String(d.getSeconds()).padStart(2, '0');

        return format
            .replace('YYYY', year)
            .replace('MM', month)
            .replace('DD', day)
            .replace('HH', hours)
            .replace('mm', minutes)
            .replace('ss', seconds);
    }

    /**
     * 获取相对时间描述
     */
    static getRelativeTime(date) {
        const now = new Date();
        const target = new Date(date);
        const diff = now - target;
        const seconds = Math.floor(diff / 1000);
        const minutes = Math.floor(seconds / 60);
        const hours = Math.floor(minutes / 60);
        const days = Math.floor(hours / 24);

        if (seconds < 60) {
            return '刚刚';
        } else if (minutes < 60) {
            return `${minutes}分钟前`;
        } else if (hours < 24) {
            return `${hours}小时前`;
        } else if (days < 7) {
            return `${days}天前`;
        } else {
            return this.format(date, 'YYYY-MM-DD');
        }
    }

    /**
     * 判断是否为今天
     */
    static isToday(date) {
        const today = new Date();
        const target = new Date(date);
        return today.getFullYear() === target.getFullYear() &&
               today.getMonth() === target.getMonth() &&
               today.getDate() === target.getDate();
    }

    /**
     * 获取时间戳
     */
    static timestamp(date = new Date()) {
        return new Date(date).getTime();
    }

    /**
     * 获取唯一ID
     */
    static generateId() {
        return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    }
}

export default DateUtils;

/**
 * Todo 项数据模型
 */

import DateUtils from '../utils/dateUtils.js';

class Todo {
    /**
     * 创建 Todo 实例
     */
    constructor(data = {}) {
        this.id = data.id || DateUtils.generateId();
        this.text = data.text || '';
        this.completed = data.completed || false;
        this.createdAt = data.createdAt || DateUtils.timestamp();
        this.updatedAt = data.updatedAt || DateUtils.timestamp();
        this.order = data.order || 0;
    }

    /**
     * 切换完成状态
     */
    toggle() {
        this.completed = !this.completed;
        this.updatedAt = DateUtils.timestamp();
        return this;
    }

    /**
     * 更新文本
     */
    updateText(newText) {
        if (newText && newText.trim()) {
            this.text = newText.trim();
            this.updatedAt = DateUtils.timestamp();
            return true;
        }
        return false;
    }

    /**
     * 设置完成状态
     */
    setCompleted(completed) {
        this.completed = completed;
        this.updatedAt = DateUtils.timestamp();
        return this;
    }

    /**
     * 设置排序位置
     */
    setOrder(order) {
        this.order = order;
        this.updatedAt = DateUtils.timestamp();
        return this;
    }

    /**
     * 转换为 JSON
     */
    toJSON() {
        return {
            id: this.id,
            text: this.text,
            completed: this.completed,
            createdAt: this.createdAt,
            updatedAt: this.updatedAt,
            order: this.order
        };
    }

    /**
     * 从 JSON 创建实例
     */
    static fromJSON(json) {
        return new Todo(json);
    }

    /**
     * 验证 Todo 是否有效
     */
    isValid() {
        return this.text && this.text.trim().length > 0;
    }
}

export default Todo;

/**
 * TodoList 集合模型
 * 管理多个 Todo 项
 */

import Todo from './Todo.js';
import storage from '../utils/storage.js';

class TodoList {
    constructor() {
        this.todos = [];
        this.filter = 'all'; // all, active, completed
        this.load();
    }

    /**
     * 加载数据
     */
    load() {
        const data = storage.get('todos', []);
        this.todos = data.map(item => Todo.fromJSON(item));
        this.sort();
    }

    /**
     * 保存数据
     */
    save() {
        const data = this.todos.map(todo => todo.toJSON());
        storage.set('todos', data);
    }

    /**
     * 获取所有 Todo
     */
    getAll() {
        return [...this.todos];
    }

    /**
     * 根据 filter 获取 Todo
     */
    getFiltered() {
        switch (this.filter) {
            case 'active':
                return this.todos.filter(todo => !todo.completed);
            case 'completed':
                return this.todos.filter(todo => todo.completed);
            default:
                return this.getAll();
        }
    }

    /**
     * 设置过滤器
     */
    setFilter(filter) {
        this.filter = filter;
    }

    /**
     * 添加 Todo
     */
    add(text) {
        const todo = new Todo({ text });
        this.todos.push(todo);
        this.save();
        return todo;
    }

    /**
     * 删除 Todo
     */
    remove(id) {
        const index = this.todos.findIndex(todo => todo.id === id);
        if (index !== -1) {
            this.todos.splice(index, 1);
            this.save();
            return true;
        }
        return false;
    }

    /**
     * 更新 Todo
     */
    update(id, updates) {
        const todo = this.findById(id);
        if (todo) {
            Object.assign(todo, updates);
            todo.updatedAt = Date.now();
            this.save();
            return todo;
        }
        return null;
    }

    /**
     * 切换 Todo 状态
     */
    toggle(id) {
        const todo = this.findById(id);
        if (todo) {
            todo.toggle();
            this.save();
            return todo;
        }
        return null;
    }

    /**
     * 根据 ID 查找 Todo
     */
    findById(id) {
        return this.todos.find(todo => todo.id === id);
    }

    /**
     * 清除已完成的 Todo
     */
    clearCompleted() {
        const beforeCount = this.todos.length;
        this.todos = this.todos.filter(todo => !todo.completed);
        const afterCount = this.todos.length;
        this.save();
        return beforeCount - afterCount;
    }

    /**
     * 获取统计信息
     */
    getStats() {
        const total = this.todos.length;
        const completed = this.todos.filter(todo => todo.completed).length;
        const active = total - completed;

        return {
            total,
            completed,
            active,
            completionRate: total > 0 ? Math.round((completed / total) * 100) : 0
        };
    }

    /**
     * 排序
     */
    sort() {
        this.todos.sort((a, b) => {
            if (a.order !== b.order) {
                return a.order - b.order;
            }
            return b.createdAt - a.createdAt;
        });
    }

    /**
     * 重新排序
     */
    reorder(sourceIndex, destinationIndex) {
        const [removed] = this.todos.splice(sourceIndex, 1);
        this.todos.splice(destinationIndex, 0, removed);
        this.save();
    }

    /**
     * 搜索 Todo
     */
    search(query) {
        const lowerQuery = query.toLowerCase();
        return this.todos.filter(todo => 
            todo.text.toLowerCase().includes(lowerQuery)
        );
    }

    /**
     * 获取所有标签
     */
    getTags() {
        const tags = new Set();
        this.todos.forEach(todo => {
            const matches = todo.text.match(/#(\w+)/g);
            if (matches) {
                matches.forEach(match => tags.add(match.substring(1)));
            }
        });
        return Array.from(tags);
    }
}

export default TodoList;

/**
 * 单个 Todo 项视图类
 * 负责渲染和更新单个 Todo 项的 UI
 */

import DOMHelper from '../utils/domHelper.js';

class TodoView {
    constructor(todo) {
        this.todo = todo;
        this.element = null;
        this.isEditing = false;
    }

    /**
     * 渲染 Todo 项
     */
    render() {
        if (this.element) {
            this.update();
            return this.element;
        }

        this.element = DOMHelper.createElement('li', 'todo-item');
        this.element.setAttribute('data-id', this.todo.id);

        // 复选框
        const checkbox = DOMHelper.createElement('div', 'todo-checkbox');
        if (this.todo.completed) {
            DOMHelper.addClass(checkbox, 'checked');
        }
        DOMHelper.on(checkbox, 'click', () => this.onToggle());

        // 文本容器
        const textContainer = DOMHelper.createElement('div', 'todo-text-container');

        // 文本内容
        const text = DOMHelper.createElement('span', 'todo-text', this.todo.text);
        if (this.todo.completed) {
            DOMHelper.addClass(text, 'completed');
        }

        // 编辑输入框（默认隐藏）
        const editInput = DOMHelper.createElement('input', 'todo-edit-input');
        editInput.type = 'text';
        editInput.value = this.todo.text;
        DOMHelper.hide(editInput);

        // 按钮容器
        const actions = DOMHelper.createElement('div', 'todo-actions');

        // 编辑按钮
        const editBtn = DOMHelper.createElement('button', 'todo-edit');
        editBtn.setAttribute('aria-label', '编辑');
        editBtn.textContent = '✏️';
        DOMHelper.on(editBtn, 'click', () => this.onEdit());

        // 删除按钮
        const deleteBtn = DOMHelper.createElement('button', 'todo-delete');
        deleteBtn.setAttribute('aria-label', '删除');
        deleteBtn.textContent = '🗑️';
        DOMHelper.on(deleteBtn, 'click', () => this.onDelete());

        // 组装元素
        actions.appendChild(editBtn);
        actions.appendChild(deleteBtn);
        textContainer.appendChild(text);
        textContainer.appendChild(editInput);
        this.element.appendChild(checkbox);
        this.element.appendChild(textContainer);
        this.element.appendChild(actions);

        // 绑定回车键保存编辑
        DOMHelper.on(editInput, 'keydown', (e) => {
            if (e.key === 'Enter') {
                this.saveEdit();
            } else if (e.key === 'Escape') {
                this.cancelEdit();
            }
        });

        // 绑定失焦保存
        DOMHelper.on(editInput, 'blur', () => {
            if (this.isEditing) {
                this.saveEdit();
            }
        });

        return this.element;
    }

    /**
     * 更新 Todo 项
     */
    update() {
        if (!this.element) return;

        const checkbox = this.element.querySelector('.todo-checkbox');
        const text = this.element.querySelector('.todo-text');

        if (this.todo.completed) {
            DOMHelper.addClass(checkbox, 'checked');
            DOMHelper.addClass(this.element, 'completed');
            DOMHelper.addClass(text, 'completed');
        } else {
            DOMHelper.removeClass(checkbox, 'checked');
            DOMHelper.removeClass(this.element, 'completed');
            DOMHelper.removeClass(text, 'completed');
        }

        text.textContent = this.todo.text;
    }

    /**
     * 切换完成状态
     */
    onToggle() {
        if (this.onToggleCallback) {
            this.onToggleCallback(this.todo.id);
        }
    }

    /**
     * 编辑
     */
    onEdit() {
        this.startEdit();
    }

    /**
     * 开始编辑
     */
    startEdit() {
        this.isEditing = true;
        const textElement = this.element.querySelector('.todo-text');
        const editInput = this.element.querySelector('.todo-edit-input');

        DOMHelper.hide(textElement);
        DOMHelper.show(editInput);
        editInput.value = this.todo.text;
        editInput.focus();
        editInput.select();

        DOMHelper.addClass(this.element, 'editing');
    }

    /**
     * 保存编辑
     */
    saveEdit() {
        if (!this.isEditing) return;

        const editInput = this.element.querySelector('.todo-edit-input');
        const newText = editInput.value.trim();

        if (newText && this.onUpdateCallback) {
            this.onUpdateCallback(this.todo.id, newText);
        }

        this.cancelEdit();
    }

    /**
     * 取消编辑
     */
    cancelEdit() {
        this.isEditing = false;
        const textElement = this.element.querySelector('.todo-text');
        const editInput = this.element.querySelector('.todo-edit-input');

        DOMHelper.show(textElement);
        DOMHelper.hide(editInput);
        DOMHelper.removeClass(this.element, 'editing');
    }

    /**
     * 删除
     */
    onDelete() {
        if (this.onDeleteCallback) {
            this.onDeleteCallback(this.todo.id);
        }
    }

    /**
     * 设置回调函数
     */
    onToggle(callback) {
        this.onToggleCallback = callback;
    }

    onUpdate(callback) {
        this.onUpdateCallback = callback;
    }

    onDelete(callback) {
        this.onDeleteCallback = callback;
    }

    /**
     * 销毁元素
     */
    destroy() {
        if (this.element && this.element.parentNode) {
            this.element.parentNode.removeChild(this.element);
        }
        this.element = null;
    }
}

export default TodoView;

/**
 * 列表视图类
 * 负责渲染和管理整个 Todo 列表
 */

import DOMHelper from '../utils/domHelper.js';
import TodoView from './TodoView.js';

class ListView {
    constructor(todoList) {
        this.todoList = todoList;
        this.container = null;
        this.emptyState = null;
        this.todoViews = new Map();
    }

    /**
     * 初始化视图
     */
    init(containerId, emptyStateId) {
        this.container = DOMHelper.$(containerId);
        this.emptyState = DOMHelper.$(emptyStateId);
        this.render();
    }

    /**
     * 渲染列表
     */
    render() {
        if (!this.container) return;

        // 清空现有视图
        this.todoViews.clear();
        this.container.innerHTML = '';

        const todos = this.todoList.getFiltered();

        if (todos.length === 0) {
            this.showEmptyState();
        } else {
            this.hideEmptyState();
            todos.forEach(todo => {
                this.addTodoView(todo);
            });
        }

        this.updateStats();
    }

    /**
     * 添加 Todo 视图
     */
    addTodoView(todo) {
        const view = new TodoView(todo);

        // 设置回调
        view.onToggle((id) => this.onTodoToggle(id));
        view.onUpdate((id, text) => this.onTodoUpdate(id, text));
        view.onDelete((id) => this.onTodoDelete(id));

        const element = view.render();
        this.container.appendChild(element);
        this.todoViews.set(todo.id, view);

        // 添加动画
        DOMHelper.animate(element, 'slideIn', 300);
    }

    /**
     * 更新 Todo 视图
     */
    updateTodoView(id) {
        const view = this.todoViews.get(id);
        if (view) {
            view.update();
            this.updateStats();
        }
    }

    /**
     * 删除 Todo 视图
     */
    removeTodoView(id) {
        const view = this.todoViews.get(id);
        if (view) {
            DOMHelper.animate(view.element, 'slideOut', 300);
            setTimeout(() => {
                view.destroy();
                this.todoViews.delete(id);

                // 检查是否显示空状态
                if (this.todoViews.size === 0) {
                    this.showEmptyState();
                }

                this.updateStats();
            }, 300);
        }
    }

    /**
     * 显示空状态
     */
    showEmptyState() {
        if (this.emptyState) {
            DOMHelper.show(this.emptyState);
        }
    }

    /**
     * 隐藏空状态
     */
    hideEmptyState() {
        if (this.emptyState) {
            DOMHelper.hide(this.emptyState);
        }
    }

    /**
     * 更新统计信息
     */
    updateStats() {
        const stats = this.todoList.getStats();

        const totalCount = DOMHelper.$('#total-count');
        const completedCount = DOMHelper.$('#completed-count');

        if (totalCount) {
            DOMHelper.setText(totalCount, stats.total);
        }

        if (completedCount) {
            DOMHelper.setText(completedCount, stats.completed);
        }
    }

    /**
     * 处理 Todo 切换
     */
    onTodoToggle(id) {
        this.todoList.toggle(id);
        this.updateTodoView(id);
    }

    /**
     * 处理 Todo 更新
     */
    onTodoUpdate(id, text) {
        if (this.todoList.update(id, { text })) {
            this.updateTodoView(id);
        }
    }

    /**
     * 处理 Todo 删除
     */
    onTodoDelete(id) {
        this.todoList.remove(id);
        this.removeTodoView(id);
    }

    /**
     * 添加新 Todo
     */
    addTodo(text) {
        const todo = this.todoList.add(text);

        // 如果当前过滤器不显示新添加的 todo，则切换到 'all'
        if (this.todoList.filter !== 'all' && this.todoList.filter !== 'active') {
            this.todoList.setFilter('all');
            this.render();
        } else {
            this.hideEmptyState();
            this.addTodoView(todo);
            this.updateStats();
        }
    }

    /**
     * 清除已完成
     */
    clearCompleted() {
        const completed = this.todoList.getAll().filter(todo => todo.completed);
        completed.forEach(todo => {
            this.removeTodoView(todo.id);
        });

        setTimeout(() => {
            this.todoList.clearCompleted();
            this.render();
        }, 300);
    }

    /**
     * 设置过滤器
     */
    setFilter(filter) {
        this.todoList.setFilter(filter);
        this.render();
    }

    /**
     * 销毁视图
     */
    destroy() {
        this.todoViews.forEach(view => view.destroy());
        this.todoViews.clear();
        if (this.container) {
            this.container.innerHTML = '';
        }
    }
}

export default ListView;

/**
 * Todo 控制器类
 * 处理 Todo 相关的业务逻辑
 */

import DOMHelper from '../utils/domHelper.js';

class TodoController {
    constructor(todoList, listView) {
        this.todoList = todoList;
        this.listView = listView;
        this.form = null;
        this.input = null;
        this.init();
    }

    /**
     * 初始化控制器
     */
    init() {
        this.form = DOMHelper.$('#todo-form');
        this.input = DOMHelper.$('#todo-input');

        this.bindEvents();
    }

    /**
     * 绑定事件
     */
    bindEvents() {
        if (this.form) {
            DOMHelper.on(this.form, 'submit', (e) => this.handleSubmit(e));
        }
    }

    /**
     * 处理表单提交
     */
    handleSubmit(e) {
        e.preventDefault();

        const text = this.input.value.trim();
        if (text) {
            this.addTodo(text);
            this.input.value = '';
            this.input.focus();
        }
    }

    /**
     * 添加 Todo
     */
    addTodo(text) {
        this.listView.addTodo(text);
    }

    /**
     * 清除已完成的 Todo
     */
    clearCompleted() {
        this.listView.clearCompleted();
    }

    /**
     * 设置过滤器
     */
    setFilter(filter) {
        this.listView.setFilter(filter);
    }

    /**
     * 获取统计信息
     */
    getStats() {
        return this.todoList.getStats();
    }
}

