/**
 * UI 控制器类
 * 处理 UI 交互和主题切换
 */

import DOMHelper from '../utils/domHelper.js';
import storage from '../utils/storage.js';

class UIController {
    constructor() {
        this.theme = storage.get('theme', 'light');
        this.themeToggle = null;
        this.filterButtons = null;
        this.clearButton = null;
        this.onFilterChange = null;
        this.onClearCompleted = null;
    }

    /**
     * 初始化 UI 控制器
     */
    init() {
        this.themeToggle = DOMHelper.$('#theme-toggle');
        this.filterButtons = DOMHelper.$$('.filter-btn');
        this.clearButton = DOMHelper.$('#clear-completed');

        this.applyTheme();
        this.bindEvents();
    }

    /**
     * 绑定事件
     */
    bindEvents() {
        // 主题切换
        if (this.themeToggle) {
            DOMHelper.on(this.themeToggle, 'click', () => this.toggleTheme());
        }

        // 过滤按钮
        this.filterButtons.forEach(button => {
            DOMHelper.on(button, 'click', () => {
                const filter = DOMHelper.getAttribute(button, 'data-filter');
                this.setActiveFilter(button);
                if (this.onFilterChange) {
                    this.onFilterChange(filter);
                }
            });
        });

        // 清除已完成按钮
        if (this.clearButton) {
            DOMHelper.on(this.clearButton, 'click', () => {
                if (this.onClearCompleted) {
                    this.onClearCompleted();
                }
            });
        }
    }

    /**
     * 切换主题
     */
    toggleTheme() {
        this.theme = this.theme === 'light' ? 'dark' : 'light';
        storage.set('theme', this.theme);
        this.applyTheme();
    }

    /**
     * 应用主题
     */
    applyTheme() {
        const icon = this.themeToggle ? this.themeToggle.querySelector('.theme-icon') : null;

        if (this.theme === 'dark') {
            DOMHelper.setAttribute(document.documentElement, 'data-theme', 'dark');
            if (icon) icon.textContent = '☀️';
        } else {
            DOMHelper.removeAttribute(document.documentElement, 'data-theme');
            if (icon) icon.textContent = '🌙';
        }
    }

    /**
     * 设置活动过滤器
     */
    setActiveFilter(activeButton) {
        this.filterButtons.forEach(button => {
            DOMHelper.removeClass(button, 'active');
        });
        DOMHelper.addClass(activeButton, 'active');
    }

    /**
     * 设置过滤器变更回调
     */
    onFilterChange(callback) {
        this.onFilterChange = callback;
    }

    /**
     * 设置清除已完成回调
     */
    onClearCompleted(callback) {
        this.onClearCompleted = callback;
    }

    /**
     * 显示通知
     */
    showNotification(message, type = 'info') {
        const notification = DOMHelper.createElement('div', `notification notification-${type}`, message);
        DOMHelper.addClass(notification, 'notification');

        document.body.appendChild(notification);

        DOMHelper.fadeIn(notification);

        setTimeout(() => {
            DOMHelper.fadeOut(notification);
            setTimeout(() => {
                if (notification.parentNode) {
                    notification.parentNode.removeChild(notification);
                }
            }, 300);
        }, 2000);
    }

    /**
     * 显示确认对话框
     */
    showConfirm(message, callback) {
        const confirmed = confirm(message);
        if (confirmed && callback) {
            callback();
        }
    }

    /**
     * 设置加载状态
     */
    setLoading(isLoading) {
        const submitButton = DOMHelper.$('#todo-form button[type="submit"]');
        if (submitButton) {
            if (isLoading) {
                DOMHelper.addClass(submitButton, 'loading');
                submitButton.disabled = true;
            } else {
                DOMHelper.removeClass(submitButton, 'loading');
                submitButton.disabled = false;
            }
        }
    }
}

export default UIController;

/**
 * 主入口文件
 * 初始化并协调各个模块
 */

import TodoList from './models/TodoList.js';
import ListView from './views/ListView.js';
