import UIController from './controllers/UIController.js';

class App {
    constructor() {
        this.todoList = null;
        this.listView = null;
        this.todoController = null;
        this.uiController = null;
    }

    /**
     * 初始化应用
     */
    init() {
        // 创建数据模型
        this.todoList = new TodoList();

        // 创建列表视图
        this.listView = new ListView(this.todoList);
        this.listView.init('#todo-list', '#empty-state');

        // 创建 Todo 控制器
        this.todoController = new TodoController(this.todoList, this.listView);

        // 创建 UI 控制器
        this.uiController = new UIController();
        this.uiController.init();

        // 连接 UI 控制器和业务逻辑
        this.connectControllers();

        // 添加示例数据（如果是首次使用）
        this.addWelcomeData();

        console.log('✅ TODOList 应用初始化完成！');
    }

    /**
     * 连接控制器
     */
    connectControllers() {
        // UI 控制器 → Todo 控制器
        this.uiController.onFilterChange((filter) => {
            this.todoController.setFilter(filter);
        });

        this.uiController.onClearCompleted(() => {
            this.uiController.showConfirm(
                '确定要清除所有已完成的待办事项吗？',
                () => {
                    this.todoController.clearCompleted();
                    this.uiController.showNotification('已清除所有待办事项', 'success');
                }
            );
        });
    }

    /**
     * 添加欢迎数据
     */
    addWelcomeData() {
        if (this.todoList.getAll().length === 0) {
            const welcomeTodos = [
                '👋 欢迎使用 TODOList！',
                '✨ 这是一个简洁的待办事项管理应用',
                '🎯 点击复选框标记完成状态',
                '✏️ 点击编辑按钮修改待办事项',
                '🗑️ 点击删除按钮移除待办事项',
                '🌙 点击右上角切换深色模式'
            ];

            welcomeTodos.forEach((text, index) => {
