import DateUtils from '../utils/dateUtils.js';

class Todo {
    /**
     * 创建 Todo 实例
     */
    constructor(data = {}) {
        this.id = data.id || DateUtils.generateId();
        this.text = data.text || '';
        this.completed = data.completed || false;
        this.createdAt = data.createdAt || DateUtils.timestamp();
        this.updatedAt = data.updatedAt || DateUtils.timestamp();
        this.order = data.order || 0;
    }

    /**
     * 切换完成状态
     */
    toggle() {
        this.completed = !this.completed;
        this.updatedAt = DateUtils.timestamp();
        return this;
    }

    /**
     * 更新文本
     */
    updateText(newText) {
        if (newText && newText.trim()) {
            this.text = newText.trim();
            this.updatedAt = DateUtils.timestamp();
            return true;
        }
        return false;
    }

    /**
     * 设置完成状态
     */
    setCompleted(completed) {
        this.completed = completed;
        this.updatedAt = DateUtils.timestamp();
        return this;
    }

    /**
     * 设置排序位置
     */
    setOrder(order) {
        this.order = order;
        this.updatedAt = DateUtils.timestamp();
        return this;
    }

    /**
     * 转换为 JSON
     */
    toJSON() {
        return {
            id: this.id,
            text: this.text,
            completed: this.completed,
            createdAt: this.createdAt,
            updatedAt: this.updatedAt,
            order: this.order
        };
    }

    /**
     * 从 JSON 创建实例
     */
    static fromJSON(json) {
        return new Todo(json);
    }

    /**
     * 验证 Todo 是否有效
     */
    isValid() {
        return this.text && this.text.trim().length > 0;
    }
}

export default Todo;

/**
 * TodoList 集合模型
 * 管理多个 Todo 项
 */

import Todo from './Todo.js';
import storage from '../utils/storage.js';

class TodoList {
    constructor() {
        this.todos = [];
        this.filter = 'all'; // all, active, completed
        this.load();
    }

    /**
     * 加载数据
     */
    load() {
        const data = storage.get('todos', []);
        this.todos = data.map(item => Todo.fromJSON(item));
        this.sort();
    }

    /**
     * 保存数据
     */
    save() {
        const data = this.todos.map(todo => todo.toJSON());
        storage.set('todos', data);
    }

    /**
     * 获取所有 Todo
     */
    getAll() {
        return [...this.todos];
    }

    /**
     * 根据 filter 获取 Todo
     */
    getFiltered() {
        switch (this.filter) {
            case 'active':
                return this.todos.filter(todo => !todo.completed);
            case 'completed':
                return this.todos.filter(todo => todo.completed);
            default:
                return this.getAll();
        }
    }

    /**
     * 设置过滤器
     */
    setFilter(filter) {
        this.filter = filter;
    }

    /**
     * 添加 Todo
     */
    add(text) {
        const todo = new Todo({ text });
        this.todos.push(todo);
        this.save();
        return todo;
    }

    /**
     * 删除 Todo
     */
    remove(id) {
        const index = this.todos.findIndex(todo => todo.id === id);
        if (index !== -1) {
            this.todos.splice(index, 1);
            this.save();
            return true;
        }
        return false;
    }

    /**
     * 更新 Todo
     */
    update(id, updates) {
        const todo = this.findById(id);
        if (todo) {
            Object.assign(todo, updates);
            todo.updatedAt = Date.now();
            this.save();
            return todo;
        }
        return null;
    }

    /**
     * 切换 Todo 状态
     */
    toggle(id) {
        const todo = this.findById(id);
        if (todo) {
            todo.toggle();
            this.save();
            return todo;
        }
        return null;
    }

    /**
     * 根据 ID 查找 Todo
     */
    findById(id) {
        return this.todos.find(todo => todo.id === id);
    }

    /**
     * 清除已完成的 Todo
     */
    clearCompleted() {
        const beforeCount = this.todos.length;
        this.todos = this.todos.filter(todo => !todo.completed);
        const afterCount = this.todos.length;
        this.save();
        return beforeCount - afterCount;
    }

    /**
     * 获取统计信息
     */
    getStats() {
        const total = this.todos.length;
        const completed = this.todos.filter(todo => todo.completed).length;
        const active = total - completed;

        return {
            total,
            completed,
            active,
            completionRate: total > 0 ? Math.round((completed / total) * 100) : 0
        };
    }

    /**
     * 排序
     */
    sort() {
        this.todos.sort((a, b) => {
            if (a.order !== b.order) {
                return a.order - b.order;
            }
            return b.createdAt - a.createdAt;
        });
    }

    /**
     * 重新排序
     */
    reorder(sourceIndex, destinationIndex) {
        const [removed] = this.todos.splice(sourceIndex, 1);
        this.todos.splice(destinationIndex, 0, removed);
        this.save();
    }

    /**
     * 搜索 Todo
     */
    search(query) {
        const lowerQuery = query.toLowerCase();
        return this.todos.filter(todo => 
            todo.text.toLowerCase().includes(lowerQuery)
        );
    }

    /**
     * 获取所有标签
     */
    getTags() {
        const tags = new Set();
        this.todos.forEach(todo => {
            const matches = todo.text.match(/#(\w+)/g);
            if (matches) {
                matches.forEach(match => tags.add(match.substring(1)));
            }
        });
        return Array.from(tags);
    }
}

export default TodoList;

